class Solution {
    public int minStartingIndex(String s, String pattern) {
        int n = s.length();
        int m = pattern.length();
        for (int i = 0; i <= n - m; i++) {
            int mismatches = 0;
            for (int j = 0; j < m; j++) {
                if (s.charAt(i + j) != pattern.charAt(j)) {
                    mismatches++;
                    if (mismatches > 1) {
                        break;
                    }
                }
            }
            if (mismatches <= 1) {
                return i;
            }
        }
        return -1;
    }
}

